import React, { useState, useEffect } from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { set_arr_robots } from '../redux/dataReducerRobot'; // פעולה לעדכון הסטור של הרובוטים
import { getAll as getAllRobots } from '../api/robotApi'; // ייבוא הפונקציה שמושכת את כל הרובוטים
import './addRobot.css';

const AddRobot = () => {
    const [robot, setRobot] = useState({
        robotName: "",
        price: 0,
        amountInStock: 0,
        category: 0,
        desc: "",
        img: ""
    });

    //לשמירת התמונה שתבחר
const [selectedFile, setSelectedFile] = useState(null);    const [categories, setCategories] = useState([]);
    //מאפשר שליחת פעולות לסטור
    const dispatch = useDispatch();
    //ניווט בין דפים
    const navigate = useNavigate();

    //שליפת כל הקטגוריות מהשרת
    useEffect(() => {
        fetch("http://localhost:8080/api/categoryApi/getAllCategories")
            .then(res => res.json())
            .then(data => setCategories(data))
            .catch(err => console.error("שגיאה בטעינת קטגוריות:", err));
    }, []);

    const handleChange = (e) => {
        const { name, value } = e.target;
        // עדכון השדה המתאים באובייקט הרובוט
        setRobot({...robot, [name]: value });
    };

    // פונקציה לטיפול בבחירת קובץ מהמחשב
const handleFileChange = (e) => {
        setSelectedFile(e.target.files[0]); // שמירת הקובץ שנבחר מהמחשב
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        // יצירת אובייקט FormData לשליחת קבצים
        const formData = new FormData();
        formData.append("robotName", robot.robotName);
        formData.append("price", robot.price);
        formData.append("amountInStock", robot.amountInStock);
        formData.append("category", robot.category);
        formData.append("desc", robot.desc);
        
        // הוספת הקובץ - השם 'img' חייב להתאים למה שהשרת מצפה לו (בדרך כלל ב-Multer)
        if (selectedFile) {
            formData.append("img", selectedFile);
        }

        try {
            const response = await fetch("http://localhost:8080/api/robotApi/postRobot", {
                method: "POST",
                // חשוב: כששולחים FormData, *לא* מגדירים Content-Type ידנית!
                body: formData 
            });
            if (response.ok) {
                //הרובוט נוסף בהצלחה
                alert("הרובוט נוסף בהצלחה!");
                //שליפת כל הרובוטים המעודכנת מהשרת
                const robots = await getAllRobots();
                //עדכון הסטור עם מערך הרובוטים המעודכן
                dispatch(set_arr_robots(robots));
                //ניווט חזרה לדף הראשי או לדף הרובוטים
                navigate("/");
            } else {
                alert("שגיאה בהוספת הרובוט.");
            }
        } catch (error) {
            console.error("שגיאה בהוספת הרובוט:", error);
        }
    };

    return (
        <div className="add-robot-page">
            <div className="add-robot-card">
                <h2>הוסף רובוט חדש</h2>
                <form onSubmit={handleSubmit} className="add-robot-form">
                    <div className="form-field">
                        <label>שם הרובוט:</label>
                        <input type="text" name="robotName" value={robot.robotName} onChange={handleChange} required />
                    </div>
                    <div className="form-field">
                        <label>מחיר:</label>
                        <input type="number" name="price" value={robot.price} onChange={handleChange} required />
                    </div>  
                    <div className="form-field">
                        <label>כמות במלאי:</label>
                        <input type="number" name="amountInStock" value={robot.amountInStock} onChange={handleChange} required />
                    </div>
                    <div className="form-field">
                        <label>קטגוריה:</label>
                        <select name="category" value={robot.category} onChange={handleChange} required>
                            <option value="">בחר קטגוריה</option>
                            {categories.map(cat => (
                                <option key={cat._id} value={cat._id}>{cat.categoryName}</option>
                            ))}
                        </select>
                    </div>
                    <div className="form-field">
                        <label>תיאור:</label>
                        <textarea name="desc" value={robot.desc} onChange={handleChange} required></textarea>
                    </div>
                    <div className="form-field">
                        <label>בחר תמונה מהמחשב:</label>
                        <input 
                            type="file" 
                            name="img" 
                            accept="image/*" 
                            onChange={handleFileChange} 
                            required 
                            className="file-input"
                        />
                    </div>
                    <button type="submit" className="submit-robot-btn">הוסף רובוט</button>
                </form>
            </div>
        </div>
    );
}

export default AddRobot;
